module dram_cell (  
    input clk,  
    input write_enable,  
    input [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] unused_storage;  

    always @(posedge clk) begin  
        if (write_enable) begin  
            unused_storage <= data_in;  
        end  
        data_out <= unused_storage;  
    end  
endmodule
